PRAGMA foreign_keys=OFF;
BEGIN TRANSACTION;
CREATE TABLE judges (
	id INTEGER NOT NULL, 
	name_normalized VARCHAR(200) NOT NULL, 
	slug VARCHAR(80), 
	first_seen DATE, 
	last_seen DATE, 
	PRIMARY KEY (id), 
	UNIQUE (slug)
);
CREATE TABLE defendants (
	id VARCHAR(64) NOT NULL, 
	PRIMARY KEY (id)
);
CREATE TABLE charge_categories (
	id INTEGER NOT NULL, 
	slug VARCHAR(60) NOT NULL, 
	name VARCHAR(120) NOT NULL, 
	PRIMARY KEY (id), 
	UNIQUE (slug)
);
CREATE TABLE raw_dockets (
	docket_number VARCHAR(40) NOT NULL, 
	pdf_path TEXT, 
	fetched_at DATETIME, 
	parse_status VARCHAR(20) NOT NULL, 
	notes TEXT, 
	PRIMARY KEY (docket_number)
);
CREATE TABLE judge_aliases (
	id INTEGER NOT NULL, 
	judge_id INTEGER NOT NULL, 
	name_raw VARCHAR(200) NOT NULL, 
	PRIMARY KEY (id), 
	FOREIGN KEY(judge_id) REFERENCES judges (id)
);
CREATE TABLE cases (
	docket_number VARCHAR(40) NOT NULL, 
	county VARCHAR(40) NOT NULL, 
	court_type VARCHAR(40) NOT NULL, 
	case_status VARCHAR(40), 
	filed_date DATE, 
	otn VARCHAR(40), 
	judge_id INTEGER, 
	assigned_judge_raw TEXT, 
	defendant_id VARCHAR(64), 
	source_url TEXT, 
	scraped_at DATETIME DEFAULT CURRENT_TIMESTAMP NOT NULL, 
	PRIMARY KEY (docket_number), 
	FOREIGN KEY(judge_id) REFERENCES judges (id), 
	FOREIGN KEY(defendant_id) REFERENCES defendants (id)
);
CREATE TABLE charges (
	id INTEGER NOT NULL, 
	docket_number VARCHAR(40) NOT NULL, 
	sequence INTEGER, 
	statute VARCHAR(60), 
	grade VARCHAR(10), 
	offense TEXT, 
	category_id INTEGER, 
	disposition_raw VARCHAR(120), 
	disposition_category VARCHAR(30), 
	disposition_date DATE, 
	disposition_judge_id INTEGER, 
	PRIMARY KEY (id), 
	FOREIGN KEY(docket_number) REFERENCES cases (docket_number), 
	FOREIGN KEY(category_id) REFERENCES charge_categories (id), 
	FOREIGN KEY(disposition_judge_id) REFERENCES judges (id)
);
CREATE TABLE sentences (
	id INTEGER NOT NULL, 
	charge_id INTEGER NOT NULL, 
	sentence_type VARCHAR(80), 
	min_days INTEGER, 
	max_days INTEGER, 
	program VARCHAR(120), 
	sentence_date DATE, 
	raw_text TEXT, 
	PRIMARY KEY (id), 
	FOREIGN KEY(charge_id) REFERENCES charges (id)
);
CREATE TABLE harvest_windows (
	week_start DATE NOT NULL, 
	week_end DATE NOT NULL, 
	total_rows INTEGER, 
	cp_criminal_rows INTEGER, 
	status VARCHAR(20) NOT NULL, 
	searched_at DATETIME, 
	notes TEXT, 
	PRIMARY KEY (week_start)
);
CREATE UNIQUE INDEX ix_judges_name_normalized ON judges (name_normalized);
CREATE UNIQUE INDEX ix_judge_aliases_name_raw ON judge_aliases (name_raw);
COMMIT;
